// ============================================================
// AUDIO MANAGER (Procedural)
// ============================================================

class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private droneOsc: OscillatorNode | null = null;
  private droneGain: GainNode | null = null;
  musicVolume = 0.8;
  sfxVolume = 1.0;

  private ensureCtx() {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVolume * 0.3;
      this.musicGain.connect(this.masterGain);
      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.masterGain);
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  startDrone() {
    const ctx = this.ensureCtx();
    if (this.droneOsc) return;
    this.droneOsc = ctx.createOscillator();
    this.droneOsc.type = 'sine';
    this.droneOsc.frequency.value = 55;
    this.droneGain = ctx.createGain();
    this.droneGain.gain.value = 0.08;
    this.droneOsc.connect(this.droneGain);
    this.droneGain.connect(this.musicGain!);
    this.droneOsc.start();

    // Add harmonic
    const h = ctx.createOscillator();
    h.type = 'sine';
    h.frequency.value = 82.5;
    const hg = ctx.createGain();
    hg.gain.value = 0.04;
    h.connect(hg);
    hg.connect(this.musicGain!);
    h.start();
  }

  stopDrone() {
    if (this.droneOsc) {
      this.droneOsc.stop();
      this.droneOsc = null;
    }
  }

  playLaunch(power: number) {
    const ctx = this.ensureCtx();
    const o = ctx.createOscillator();
    o.type = 'sawtooth';
    o.frequency.value = 200 + power * 400;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.15, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
    o.connect(g);
    g.connect(this.sfxGain!);
    o.start();
    o.stop(ctx.currentTime + 0.3);
  }

  playCollect(combo: number) {
    const ctx = this.ensureCtx();
    const baseFreq = 440 * Math.pow(2, combo / 12);
    for (let i = 0; i < 3; i++) {
      const o = ctx.createOscillator();
      o.type = 'sine';
      o.frequency.value = baseFreq * (1 + i * 0.5);
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.12, ctx.currentTime + i * 0.05);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.05 + 0.3);
      o.connect(g);
      g.connect(this.sfxGain!);
      o.start(ctx.currentTime + i * 0.05);
      o.stop(ctx.currentTime + i * 0.05 + 0.3);
    }
  }

  playCrash() {
    const ctx = this.ensureCtx();
    const bufSize = ctx.sampleRate * 0.2;
    const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
    const data = buf.getChannelData(0);
    for (let i = 0; i < bufSize; i++) data[i] = (Math.random() * 2 - 1) * (1 - i / bufSize);
    const src = ctx.createBufferSource();
    src.buffer = buf;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.2, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
    src.connect(g);
    g.connect(this.sfxGain!);
    src.start();
  }

  playCharge(progress: number) {
    const ctx = this.ensureCtx();
    const o = ctx.createOscillator();
    o.type = 'sine';
    o.frequency.value = 200 + progress * 600;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.06, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.08);
    o.connect(g);
    g.connect(this.sfxGain!);
    o.start();
    o.stop(ctx.currentTime + 0.08);
  }

  playSuccess() {
    const ctx = this.ensureCtx();
    const notes = [523, 659, 784, 1047];
    notes.forEach((freq, i) => {
      const o = ctx.createOscillator();
      o.type = 'sine';
      o.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.12, ctx.currentTime + i * 0.1);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.1 + 0.4);
      o.connect(g);
      g.connect(this.sfxGain!);
      o.start(ctx.currentTime + i * 0.1);
      o.stop(ctx.currentTime + i * 0.1 + 0.4);
    });
  }

  playFail() {
    const ctx = this.ensureCtx();
    const o = ctx.createOscillator();
    o.type = 'square';
    o.frequency.setValueAtTime(200, ctx.currentTime);
    o.frequency.linearRampToValueAtTime(80, ctx.currentTime + 0.4);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.1, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.4);
    o.connect(g);
    g.connect(this.sfxGain!);
    o.start();
    o.stop(ctx.currentTime + 0.4);
  }

  playClick() {
    const ctx = this.ensureCtx();
    const o = ctx.createOscillator();
    o.type = 'sine';
    o.frequency.value = 800;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.08, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.05);
    o.connect(g);
    g.connect(this.sfxGain!);
    o.start();
    o.stop(ctx.currentTime + 0.05);
  }

  playAchievement() {
    const ctx = this.ensureCtx();
    const notes = [659, 784, 880, 1047, 1319];
    notes.forEach((f, i) => {
      const o = ctx.createOscillator();
      o.type = 'triangle';
      o.frequency.value = f;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.1, ctx.currentTime + i * 0.08);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.08 + 0.5);
      o.connect(g);
      g.connect(this.sfxGain!);
      o.start(ctx.currentTime + i * 0.08);
      o.stop(ctx.currentTime + i * 0.08 + 0.5);
    });
  }

  setMusicVolume(v: number) {
    this.musicVolume = v;
    if (this.musicGain) this.musicGain.gain.value = v * 0.3;
  }

  setSfxVolume(v: number) {
    this.sfxVolume = v;
    if (this.sfxGain) this.sfxGain.gain.value = v;
  }
}

// ============================================================
// PARTICLE POOL
// ============================================================

class ParticlePool {
  private geometry: BufferGeometry;
  private positions: Float32Array;
  private colors: Float32Array;
  private sizes: Float32Array;
  private velocities: Vector3[] = [];
  private lifetimes: number[] = [];
  private maxLifetimes: number[] = [];
  private points: Points;
  private maxParticles: number;
  private activeCount = 0;

  constructor(scene: Object3D, maxParticles = 200) {
    this.maxParticles = maxParticles;
    this.positions = new Float32Array(maxParticles * 3);
    this.colors = new Float32Array(maxParticles * 4);
    this.sizes = new Float32Array(maxParticles);

    for (let i = 0; i < maxParticles; i++) {
      this.velocities.push(new Vector3());
      this.lifetimes.push(0);
      this.maxLifetimes.push(0);
      this.sizes[i] = 0;
    }

    this.geometry = new BufferGeometry();
    this.geometry.setAttribute('position', new Float32BufferAttribute(this.positions, 3));
    this.geometry.setAttribute('color', new Float32BufferAttribute(this.colors, 4));
    this.geometry.setAttribute('size', new Float32BufferAttribute(this.sizes, 1));

    const material = new PointsMaterial({
      size: 0.06,
      vertexColors: true,
      transparent: true,
      blending: AdditiveBlending,
      depthWrite: false,
      sizeAttenuation: true,
    });

    this.points = new Points(this.geometry, material);
    this.points.frustumCulled = false;
    scene.add(this.points);
  }

  emit(pos: Vector3, color: Color, count: number, speed = 2, lifetime = 0.8) {
    for (let i = 0; i < count; i++) {
      const idx = this.findFreeSlot();
      if (idx < 0) break;

      this.positions[idx * 3] = pos.x;
      this.positions[idx * 3 + 1] = pos.y;
      this.positions[idx * 3 + 2] = pos.z;

      this.velocities[idx].set(
        (Math.random() - 0.5) * speed,
        (Math.random() - 0.5) * speed,
        (Math.random() - 0.5) * speed,
      );

      this.colors[idx * 4] = color.r;
      this.colors[idx * 4 + 1] = color.g;
      this.colors[idx * 4 + 2] = color.b;
      this.colors[idx * 4 + 3] = 1;

      this.lifetimes[idx] = lifetime;
      this.maxLifetimes[idx] = lifetime;
      this.sizes[idx] = 0.06 + Math.random() * 0.04;
      this.activeCount = Math.max(this.activeCount, idx + 1);
    }
  }

  update(delta: number) {
    let maxActive = 0;
    for (let i = 0; i < this.activeCount; i++) {
      if (this.lifetimes[i] <= 0) continue;
      this.lifetimes[i] -= delta;
      if (this.lifetimes[i] <= 0) {
        this.sizes[i] = 0;
        continue;
      }
      maxActive = i + 1;
      const t = this.lifetimes[i] / this.maxLifetimes[i];
      this.positions[i * 3] += this.velocities[i].x * delta;
      this.positions[i * 3 + 1] += this.velocities[i].y * delta;
      this.positions[i * 3 + 2] += this.velocities[i].z * delta;
      this.colors[i * 4 + 3] = t;
      this.sizes[i] = 0.06 * t;
      this.velocities[i].multiplyScalar(0.98);
    }
    this.activeCount = maxActive;
    this.geometry.attributes.position.needsUpdate = true;
    this.geometry.attributes.color.needsUpdate = true;
    this.geometry.attributes.size.needsUpdate = true;
  }

  private findFreeSlot(): number {
    for (let i = 0; i < this.maxParticles; i++) {
      if (this.lifetimes[i] <= 0) return i;
    }
    return -1;
  }
}

// ============================================================
// LEVEL GENERATOR
// ============================================================

const PLANET_COLORS = [0x00ffff, 0xff44ff, 0xffaa00, 0x00ff88, 0xff4444, 0x8888ff, 0xffff00, 0x44aaff];

function seededRandom(seed: number): () => number {
  let s = seed;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function generateLevel(levelNum: number, mode: GameMode): LevelConfig {
  const rng = seededRandom(levelNum * 137 + (mode === 'daily' ? dateSeed() : 0));

  let wellCount: number;
  let targetCount: number;
  let probeLimit: number;
  let timeLimit: number;
  const fieldSize = 6 + Math.min(levelNum * 0.5, 6);

  switch (mode) {
    case 'classic':
      wellCount = 2 + Math.min(Math.floor(levelNum / 3), 4);
      targetCount = 3 + Math.min(levelNum, 7);
      probeLimit = targetCount + 3;
      timeLimit = 0;
      break;
    case 'slingshot':
      wellCount = 3 + Math.min(Math.floor(levelNum / 2), 5);
      targetCount = 2 + Math.min(Math.floor(levelNum / 2), 5);
      probeLimit = targetCount;
      timeLimit = 0;
      break;
    case 'time-trial':
      wellCount = 2 + Math.min(Math.floor(levelNum / 3), 3);
      targetCount = 5 + Math.min(levelNum, 10);
      probeLimit = 99;
      timeLimit = 30 + levelNum * 5;
      break;
    case 'precision':
      wellCount = 1 + Math.min(Math.floor(levelNum / 2), 3);
      targetCount = 2 + Math.min(Math.floor(levelNum / 2), 4);
      probeLimit = targetCount;
      timeLimit = 0;
      break;
    case 'chaos':
      wellCount = 5 + Math.min(levelNum, 8);
      targetCount = 4 + Math.min(levelNum, 6);
      probeLimit = targetCount + 5;
      timeLimit = 0;
      break;
    case 'zen':
      wellCount = 3 + Math.min(Math.floor(levelNum / 2), 5);
      targetCount = 0;
      probeLimit = 99;
      timeLimit = 0;
      break;
    case 'survival':
      wellCount = 2 + Math.min(Math.floor(levelNum / 2), 6);
      targetCount = 3 + levelNum;
      probeLimit = Math.max(targetCount - levelNum, 3);
      timeLimit = 60;
      break;
    case 'daily':
      wellCount = 3 + Math.floor(rng() * 4);
      targetCount = 5 + Math.floor(rng() * 5);
      probeLimit = targetCount + 2;
      timeLimit = 90;
      break;
    default:
      wellCount = 3;
      targetCount = 5;
      probeLimit = 8;
      timeLimit = 0;
  }

  const wells: LevelConfig['wells'] = [];
  for (let i = 0; i < wellCount; i++) {
    const angle = (i / wellCount) * Math.PI * 2 + rng() * 0.5;
    const dist = 3 + rng() * fieldSize * 0.5;
    wells.push({
      x: Math.cos(angle) * dist,
      y: (rng() - 0.5) * 3,
      z: -3 - Math.sin(angle) * dist,
      mass: 1 + rng() * 3,
      radius: 0.3 + rng() * 0.5,
      color: PLANET_COLORS[i % PLANET_COLORS.length],
    });
  }

  const targets: LevelConfig['targets'] = [];
  for (let i = 0; i < targetCount; i++) {
    let x: number, y: number, z: number;
    let attempts = 0;
    do {
      const angle = rng() * Math.PI * 2;
      const dist = 2 + rng() * fieldSize;
      x = Math.cos(angle) * dist;
      y = (rng() - 0.5) * 4;
      z = -3 - Math.sin(angle) * dist;
      attempts++;
    } while (attempts < 20 && wells.some(w => {
      const dx = x - w.x, dy = y - w.y, dz = z - w.z;
      return Math.sqrt(dx * dx + dy * dy + dz * dz) < w.radius + 0.5;
    }));
    targets.push({ x, y, z, points: 100 + Math.floor(rng() * 5) * 50 });
  }

  const modeNames: Record<GameMode, string> = {
    classic: 'Classic', slingshot: 'Slingshot', 'time-trial': 'Time Trial',
    precision: 'Precision', chaos: 'Chaos', zen: 'Zen', survival: 'Survival', daily: 'Daily',
  };

  return {
    wells, targets, probeLimit, timeLimit,
    name: `${modeNames[mode]} ${mode === 'daily' ? '' : `Level ${levelNum}`}`,
  };
}

function dateSeed(): number {
  const d = new Date();
  return d.getFullYear() * 10000 + (d.getMonth() + 1) * 100 + d.getDate();
}

