    { id: 'collect-500', name: 'Hoarder', desc: 'Collect 500 total targets', unlocked: false },
    { id: 'combo-10', name: 'Combo Legend', desc: 'Reach x10 combo', unlocked: false },
    { id: 'score-50k', name: 'High Scorer', desc: 'Reach 50,000 total score', unlocked: false },
    { id: 'perfect-5', name: 'Perfectionist', desc: 'Get 5 perfect levels', unlocked: false },
    { id: 'graze-02', name: 'Daredevil', desc: 'Pass within 0.2m of a planet', unlocked: false },
    { id: 'orbit-10', name: 'Orbital Master', desc: 'One probe orbits 10 times', unlocked: false },
    { id: 'slingshot-5', name: 'Gravity Wizard', desc: '5 gravity assists in one probe', unlocked: false },
    { id: 'crash-20', name: 'Crash Test', desc: 'Crash into 20 planets total', unlocked: false },
    { id: 'probes-200', name: 'Probe Master', desc: 'Launch 200 total probes', unlocked: false },
    { id: 'games-50', name: 'Veteran', desc: 'Play 50 games', unlocked: false },
    { id: 'speed-15', name: 'Warp Speed', desc: 'Clear a level under 15s', unlocked: false },
    { id: 'precision-1', name: 'Laser Focus', desc: 'Clear a Precision level', unlocked: false },
    { id: 'all-modes', name: 'Explorer', desc: 'Play every game mode', unlocked: false },
    { id: 'time-trial-1', name: 'Against the Clock', desc: 'Clear a Time Trial level', unlocked: false },
    { id: 'lvl-10', name: 'Journeyman', desc: 'Reach level 10', unlocked: false },
    { id: 'lvl-25', name: 'Expert', desc: 'Reach level 25', unlocked: false },
    { id: 'slowmo-100', name: 'Time Lord', desc: 'Use slow-mo 100 times', unlocked: false },
    { id: 'survive-20', name: 'Iron Will', desc: 'Reach wave 20 in Survival', unlocked: false },
    { id: 'streak-14', name: 'Dedicated', desc: '14-day daily challenge streak', unlocked: false },
    { id: 'score-100k', name: 'Legend', desc: 'Reach 100,000 total score', unlocked: false },
  ];

  modesPlayed = new Set<GameMode>();
  slowMoCount = 0;
  tripleStarCount = 0;
  levelsCompleted = 0;

  pendingAchievements: Achievement[] = [];

  getTrailLen(): number {
    switch (this.trailLengthSetting) {
      case 'short': return 40;
      case 'medium': return 80;
      case 'long': return 120;
    }
  }

  getPlayerTitle(): string {
    const titles = ['Cadet', 'Pilot', 'Navigator', 'Commander', 'Captain', 'Admiral', 'Voyager',
      'Explorer', 'Astronaut', 'Cosmonaut', 'Star Pilot', 'Orbital Engineer',
      'Gravity Master', 'Void Walker', 'Space Legend', 'Cosmic Sage',
      'Nebula Lord', 'Galaxy Commander', 'Universe Traveler', 'Ascended'];
    return titles[Math.min(this.playerLevel - 1, titles.length - 1)];
  }

  addXP(amount: number) {
    this.xp += amount;
    while (this.xp >= this.xpToNext) {
      this.xp -= this.xpToNext;
      this.playerLevel++;
      this.xpToNext = 100 + (this.playerLevel - 1) * 50;
    }
  }

  getStars(): number {
    if (!this.currentLevel || this.currentLevel.targets.length === 0) return 0;
    const accuracy = this.probesUsed > 0 ? this.targetsCollected / this.probesUsed : 0;
    const completion = this.targetsCollected / this.targetsTotal;
    if (completion >= 1 && accuracy >= 0.8) return 3;
    if (completion >= 0.8) return 2;
    if (completion >= 0.5) return 1;
    return 0;
  }

  checkAchievements() {
    const check = (id: string, condition: boolean) => {
      const a = this.achievements.find(a => a.id === id);
      if (a && !a.unlocked && condition) {
        a.unlocked = true;
        this.pendingAchievements.push(a);
      }
    };

    check('first-contact', this.totalTargetsCollected >= 1);
    check('orbital-5', this.levelsCompleted >= 5);
    check('sharp-100', this.probesUsed > 0 && this.targetsCollected === this.targetsTotal && this.targetsCollected === this.probesUsed);
    check('speed-30', this.elapsedTime < 30 && this.targetsCollected === this.targetsTotal && this.targetsTotal > 0);
    check('combo-5', this.bestCombo >= 5);
    check('marathon-30', this.totalPlayTime >= 1800);
    check('collect-100', this.totalTargetsCollected >= 100);
    check('zen-1', this.mode === 'zen');
    check('daily-7', this.dailyStreak >= 7);
    check('chaos-1', this.mode === 'chaos' && this.targetsCollected === this.targetsTotal);
    check('survive-10', this.mode === 'survival' && this.level >= 10);
    check('slowmo-50', this.slowMoCount >= 50);
    check('multi-5', this.probes.filter(p => p.alive).length >= 5);
    check('score-10k', this.totalScore >= 10000);
    check('star-10', this.tripleStarCount >= 10);
    check('minimalist', this.probesUsed === 1 && this.targetsCollected === this.targetsTotal && this.targetsTotal > 0);
    check('collect-500', this.totalTargetsCollected >= 500);
    check('combo-10', this.bestCombo >= 10);
    check('score-50k', this.totalScore >= 50000);
    check('perfect-5', this.perfectLevels >= 5);
    check('crash-20', this.planetsCrashedInto >= 20);
    check('probes-200', this.totalProbesLaunched >= 200);
    check('games-50', this.gamesPlayed >= 50);
    check('speed-15', this.elapsedTime < 15 && this.targetsCollected === this.targetsTotal && this.targetsTotal > 0);
    check('precision-1', this.mode === 'precision' && this.targetsCollected === this.targetsTotal);
    check('all-modes', this.modesPlayed.size >= 8);
    check('time-trial-1', this.mode === 'time-trial' && this.targetsCollected === this.targetsTotal);
    check('lvl-10', this.level >= 10);
    check('lvl-25', this.level >= 25);
    check('slowmo-100', this.slowMoCount >= 100);
    check('survive-20', this.mode === 'survival' && this.level >= 20);
    check('streak-14', this.dailyStreak >= 14);
    check('score-100k', this.totalScore >= 100000);
  }

  getRating(): string {
    const stars = this.getStars();
    if (stars === 3) return '***';
    if (stars === 2) return '**';
    if (stars === 1) return '*';
    return '--';
  }
}

