// ============================================================
// SCENE BUILDER
// ============================================================

function createStarField(scene: Object3D, count = 800): Points {
  const positions = new Float32Array(count * 3);
  const colors = new Float32Array(count * 3);
  for (let i = 0; i < count; i++) {
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.acos(2 * Math.random() - 1);
    const r = 40 + Math.random() * 60;
    positions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);
    const brightness = 0.3 + Math.random() * 0.7;
    colors[i * 3] = brightness;
    colors[i * 3 + 1] = brightness;
    colors[i * 3 + 2] = brightness * (0.8 + Math.random() * 0.4);
  }
  const geo = new BufferGeometry();
  geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
  geo.setAttribute('color', new Float32BufferAttribute(colors, 3));
  const mat = new PointsMaterial({ size: 0.15, vertexColors: true, transparent: true, sizeAttenuation: true });
  const stars = new Points(geo, mat);
  scene.add(stars);
  return stars;
}

function createGridFloor(scene: Object3D, color: number): Group {
  const gridGroup = new Group();
  const gridSize = 40;
  const gridStep = 2;
  const mat = new LineBasicMaterial({ color, transparent: true, opacity: 0.15 });

  for (let i = -gridSize; i <= gridSize; i += gridStep) {
    const geoX = new BufferGeometry();
    geoX.setAttribute('position', new Float32BufferAttribute([i, -2, -gridSize, i, -2, gridSize], 3));
    gridGroup.add(new LineSegments(geoX, mat));

    const geoZ = new BufferGeometry();
    geoZ.setAttribute('position', new Float32BufferAttribute([-gridSize, -2, i, gridSize, -2, i], 3));
    gridGroup.add(new LineSegments(geoZ, mat));
  }
  scene.add(gridGroup);
  return gridGroup;
}

function createGravityWell(scene: Object3D, config: LevelConfig['wells'][0]): GravityWell {
  const group = new Group();
  group.position.set(config.x, config.y, config.z);

  // Core planet
  const coreGeo = new SphereGeometry(config.radius, 32, 32);
  const coreMat = new MeshStandardMaterial({
    color: config.color,
    emissive: config.color,
    emissiveIntensity: 0.5,
    roughness: 0.3,
    metalness: 0.7,
  });
  const core = new Mesh(coreGeo, coreMat);
  group.add(core);

  // Glow shell
  const glowGeo = new SphereGeometry(config.radius * 1.3, 24, 24);
  const glowMat = new MeshBasicMaterial({
    color: config.color,
    transparent: true,
    opacity: 0.15,
    blending: AdditiveBlending,
    depthWrite: false,
  });
  const glowMesh = new Mesh(glowGeo, glowMat);
  group.add(glowMesh);

  // Orbital ring
  const ringGeo = new TorusGeometry(config.radius * 2, 0.02, 8, 64);
  const ringMat = new MeshBasicMaterial({
    color: config.color,
    transparent: true,
    opacity: 0.3,
  });
  const ringMesh = new Mesh(ringGeo, ringMat);
  ringMesh.rotation.x = Math.PI * 0.5;
  group.add(ringMesh);

  // Gravity field lines (concentric rings)
  const fieldLines: Line[] = [];
  for (let i = 0; i < 3; i++) {
    const r = config.radius * (2.5 + i * 1.5);
    const pts: number[] = [];
    const segs = 48;
    for (let j = 0; j <= segs; j++) {
      const a = (j / segs) * Math.PI * 2;
      pts.push(Math.cos(a) * r, 0, Math.sin(a) * r);
    }
    const lineGeo = new BufferGeometry();
    lineGeo.setAttribute('position', new Float32BufferAttribute(pts, 3));
    const lineMat = new LineBasicMaterial({
      color: config.color,
      transparent: true,
      opacity: 0.08 - i * 0.02,
    });
    const line = new Line(lineGeo, lineMat);
    group.add(line);
    fieldLines.push(line);
  }

  // Point light
  const light = new PointLight(config.color, 0.5, config.radius * 8);
  group.add(light);

  scene.add(group);

  return {
    group,
    position: new Vector3(config.x, config.y, config.z),
    mass: config.mass,
    radius: config.radius,
    color: config.color,
    glowMesh,
    ringMesh,
    fieldLines,
    pulsePhase: Math.random() * Math.PI * 2,
  };
}

function createTarget(scene: Object3D, config: LevelConfig['targets'][0]): Target {
  const group = new Group();
  group.position.set(config.x, config.y, config.z);

  // Octahedron core
  const geo = new OctahedronGeometry(TARGET_RADIUS, 0);
  const mat = new MeshStandardMaterial({
    color: 0x00ff88,
    emissive: 0x00ff88,
    emissiveIntensity: 0.6,
    roughness: 0.2,
    metalness: 0.8,
    wireframe: false,
  });
  const mesh = new Mesh(geo, mat);
  group.add(mesh);

  // Wireframe overlay
  const wireGeo = new OctahedronGeometry(TARGET_RADIUS * 1.2, 0);
  const wireMat = new MeshBasicMaterial({
    color: 0x00ff88,
    wireframe: true,
    transparent: true,
    opacity: 0.4,
  });
  const wire = new Mesh(wireGeo, wireMat);
  group.add(wire);

  // Glow
  const glowGeo = new SphereGeometry(TARGET_RADIUS * 2, 12, 12);
  const glowMat = new MeshBasicMaterial({
    color: 0x00ff88,
    transparent: true,
    opacity: 0.1,
    blending: AdditiveBlending,
    depthWrite: false,
  });
  group.add(new Mesh(glowGeo, glowMat));

  scene.add(group);

  return {
    group,
    position: new Vector3(config.x, config.y, config.z),
    collected: false,
    pulsePhase: Math.random() * Math.PI * 2,
    points: config.points,
  };
}

function createProbe(scene: Object3D): Probe {
  const geo = new SphereGeometry(PROBE_RADIUS, 16, 16);
  const mat = new MeshStandardMaterial({
    color: 0xff8844,
    emissive: 0xff8844,
    emissiveIntensity: 0.8,
    roughness: 0.1,
    metalness: 0.9,
  });
  const mesh = new Mesh(geo, mat);
  mesh.visible = false;
  scene.add(mesh);

  // Trail
  const trailPositions: Vector3[] = [];
  for (let i = 0; i < TRAIL_LENGTH; i++) trailPositions.push(new Vector3());
  const trailPts = new Float32Array(TRAIL_LENGTH * 3);
  const trailGeo = new BufferGeometry();
  trailGeo.setAttribute('position', new Float32BufferAttribute(trailPts, 3));
  const trailMat = new LineBasicMaterial({
    color: 0xff8844,
    transparent: true,
    opacity: 0.6,
  });
  const trailLine = new Line(trailGeo, trailMat);
  trailLine.visible = false;
  trailLine.frustumCulled = false;
  scene.add(trailLine);

  return {
    mesh,
    trailLine,
    trailPositions,
    position: new Vector3(),
    velocity: new Vector3(),
    alive: false,
    age: 0,
    orbitCount: 0,
    lastWellIdx: -1,
    closestApproach: Infinity,
  };
}

function createPredictionLine(scene: Object3D): Line {
  const pts = new Float32Array(PREDICTION_STEPS * 3);
  const geo = new BufferGeometry();
  geo.setAttribute('position', new Float32BufferAttribute(pts, 3));
  const mat = new LineBasicMaterial({
    color: 0xffffff,
    transparent: true,
    opacity: 0.3,
  });
  const line = new Line(geo, mat);
  line.visible = false;
  line.frustumCulled = false;
  scene.add(line);
  return line;
}

function createLaunchIndicator(scene: Object3D): Group {
  const group = new Group();

  // Direction arrow
  const arrowGeo = new CylinderGeometry(0.01, 0.01, 0.5, 8);
  const arrowMat = new MeshBasicMaterial({ color: 0xff8844, transparent: true, opacity: 0.6 });
  const arrow = new Mesh(arrowGeo, arrowMat);
  arrow.rotation.x = Math.PI / 2;
  arrow.position.z = -0.3;
  group.add(arrow);

  // Tip
  const tipGeo = new CylinderGeometry(0, 0.03, 0.08, 8);
  const tipMat = new MeshBasicMaterial({ color: 0xff8844, transparent: true, opacity: 0.8 });
  const tip = new Mesh(tipGeo, tipMat);
  tip.rotation.x = Math.PI / 2;
  tip.position.z = -0.55;
  group.add(tip);

  group.visible = false;
  scene.add(group);
  return group;
}

// ============================================================
// GRAVITY SIMULATION
// ============================================================

const _tempVec = new Vector3();
const _tempVec2 = new Vector3();

function computeGravity(pos: Vector3, wells: GravityWell[], out: Vector3): void {
  out.set(0, 0, 0);
  for (const well of wells) {
    _tempVec.subVectors(well.position, pos);
    const distSq = _tempVec.lengthSq();
    const dist = Math.sqrt(distSq);
    if (dist < well.radius * 0.5) continue; // Inside planet
    const force = G_CONSTANT * well.mass / Math.max(distSq, 0.1);
    _tempVec.normalize().multiplyScalar(force);
    out.add(_tempVec);
  }
}

function simulateTrajectory(
  startPos: Vector3,
  startVel: Vector3,
  wells: GravityWell[],
  steps: number,
  dt: number,
  outPositions: Float32Array,
): number {
  const pos = startPos.clone();
  const vel = startVel.clone();
  const accel = new Vector3();
  let validSteps = 0;

  for (let i = 0; i < steps; i++) {
    computeGravity(pos, wells, accel);
    vel.addScaledVector(accel, dt);
    pos.addScaledVector(vel, dt);

    outPositions[i * 3] = pos.x;
    outPositions[i * 3 + 1] = pos.y;
    outPositions[i * 3 + 2] = pos.z;
    validSteps++;

    // Check collision with wells
    for (const well of wells) {
      if (pos.distanceTo(well.position) < well.radius) return validSteps;
    }
    // Check out of bounds
    if (pos.length() > MAX_DISTANCE * 1.5) return validSteps;
  }
  return validSteps;
}

