// ============================================================
// ECS SYSTEMS
// ============================================================

// Orbit Physics System - handles gravity simulation, probe movement, collisions
class OrbitPhysicsSystem extends createSystem({
  panels: { required: [PanelUI, PanelDocument] },
}) {
  private game!: GameManager;
  private audio!: AudioManager;
  private particles!: ParticlePool;
  private probes: Probe[] = [];
  private wells: GravityWell[] = [];
  private targets: Target[] = [];
  private accel = new Vector3();

  setRefs(refs: { game: GameManager; audio: AudioManager; particles: ParticlePool; probes: Probe[]; wells: GravityWell[]; targets: Target[] }) {
    this.game = refs.game;
    this.audio = refs.audio;
    this.particles = refs.particles;
    this.probes = refs.probes;
    this.wells = refs.wells;
    this.targets = refs.targets;
  }

  update(delta: number, _time: number) {
    if (this.game.state !== 'playing') return;

    const dt = delta * this.game.timeScale;
    this.game.elapsedTime += dt;
    this.game.totalPlayTime += delta;

    // Check time limit
    if (this.game.currentLevel && this.game.currentLevel.timeLimit > 0 &&
      this.game.elapsedTime >= this.game.currentLevel.timeLimit) {
      this.endLevel();
      return;
    }

    // Update probes
    for (const probe of this.probes) {
      if (!probe.alive) continue;
      probe.age += dt;

      // Compute gravity
      computeGravity(probe.position, this.wells, this.accel);
      probe.velocity.addScaledVector(this.accel, dt);
      probe.position.addScaledVector(probe.velocity, dt);
      probe.mesh.position.copy(probe.position);

      // Update trail
      probe.trailPositions.pop();
      probe.trailPositions.unshift(probe.position.clone());
      const trailLen = this.game.getTrailLen();
      const posArr = probe.trailLine.geometry.attributes.position.array as Float32Array;
      for (let i = 0; i < TRAIL_LENGTH; i++) {
        const tp = i < trailLen ? probe.trailPositions[i] : probe.trailPositions[Math.min(i, trailLen - 1)];
        posArr[i * 3] = tp.x;
        posArr[i * 3 + 1] = tp.y;
        posArr[i * 3 + 2] = tp.z;
      }
      probe.trailLine.geometry.attributes.position.needsUpdate = true;

      // Track orbit count (detect when probe passes around a well)
      for (let wi = 0; wi < this.wells.length; wi++) {
        const well = this.wells[wi];
        const dist = probe.position.distanceTo(well.position);

        // Track closest approach
        if (dist < probe.closestApproach) probe.closestApproach = dist;

        // Detect orbit: when probe transitions from one side to another of a well
        if (dist < well.radius * 4 && wi !== probe.lastWellIdx) {
          if (probe.lastWellIdx >= 0) probe.orbitCount++;
          probe.lastWellIdx = wi;
        }
      }

      // Check collision with gravity wells
      let crashed = false;
      for (const well of this.wells) {
        if (probe.position.distanceTo(well.position) < well.radius) {
          crashed = true;
          this.audio.playCrash();
          this.particles.emit(probe.position, new Color(well.color), 30, 3, 0.6);
          this.game.planetsCrashedInto++;
          break;
        }
      }

      // Check out of bounds
      if (probe.position.length() > MAX_DISTANCE) {
        crashed = true;
      }

      if (crashed) {
        this.killProbe(probe);
        continue;
      }

      // Check target collection
      for (const target of this.targets) {
        if (target.collected) continue;
        if (probe.position.distanceTo(target.position) < TARGET_RADIUS + PROBE_RADIUS + 0.15) {
          this.collectTarget(target, probe);
        }
      }

      // Check achievements for individual probe
      if (probe.orbitCount >= 3) this.game.checkAchievements();
      if (probe.closestApproach < 0.5 && probe.closestApproach > 0) {
        const a = this.game.achievements.find(a => a.id === 'graze-05');
        if (a && !a.unlocked) {
          a.unlocked = true;
          this.game.pendingAchievements.push(a);
        }
      }
      if (probe.closestApproach < 0.2 && probe.closestApproach > 0) {
        const a = this.game.achievements.find(a => a.id === 'graze-02');
        if (a && !a.unlocked) {
          a.unlocked = true;
          this.game.pendingAchievements.push(a);
        }
      }
      if (probe.orbitCount >= 10) {
        const a = this.game.achievements.find(a => a.id === 'orbit-10');
        if (a && !a.unlocked) {
          a.unlocked = true;
          this.game.pendingAchievements.push(a);
        }
      }
    }

    // Achievement: multi-5
    const aliveCount = this.probes.filter(p => p.alive).length;
    if (aliveCount >= 5) this.game.checkAchievements();

    // Update particles
    this.particles.update(dt);

    // Animate gravity wells
    for (const well of this.wells) {
      well.pulsePhase += dt * 2;
      const pulse = 0.15 + Math.sin(well.pulsePhase) * 0.05;
      (well.glowMesh.material as MeshBasicMaterial).opacity = pulse;
      well.ringMesh.rotation.z += dt * 0.3;
      well.fieldLines.forEach((line, i) => {
        line.rotation.y += dt * (0.1 + i * 0.05);
      });
    }

    // Animate targets
    for (const target of this.targets) {
      if (target.collected) continue;
      target.pulsePhase += dt * 3;
      target.group.rotation.y += dt;
      target.group.rotation.x += dt * 0.5;
      const scale = 1 + Math.sin(target.pulsePhase) * 0.15;
      target.group.scale.setScalar(scale);
    }

    // Check level complete
    if (this.game.mode !== 'zen') {
      const allCollected = this.targets.length > 0 && this.targets.every(t => t.collected);
      const noProbesLeft = this.game.probesRemaining <= 0 && !this.probes.some(p => p.alive);
      if (allCollected || noProbesLeft) {
        this.endLevel();
      }
    }
  }

  private collectTarget(target: Target, probe: Probe) {
    target.collected = true;
    target.group.visible = false;
    this.game.targetsCollected++;
    this.game.totalTargetsCollected++;

    // Combo
    const now = this.game.elapsedTime;
    if (now - this.game.lastCollectTime < COMBO_WINDOW) {
      this.game.combo++;
    } else {
      this.game.combo = 1;
    }
    this.game.lastCollectTime = now;
    if (this.game.combo > this.game.bestCombo) this.game.bestCombo = this.game.combo;
    if (this.game.combo > this.game.allTimeBestCombo) this.game.allTimeBestCombo = this.game.combo;

    const points = target.points * this.game.combo;
    this.game.score += points;
    this.game.totalScore += points;

    this.audio.playCollect(this.game.combo);
    this.particles.emit(target.position, new Color(0x00ff88), 25, 4, 1.0);

    // Achievement: efficient pilot
    const probeTargets = this.targets.filter(t => t.collected).length;
    if (probeTargets >= 3 && this.game.probesUsed === 1) {
      const a = this.game.achievements.find(a => a.id === 'efficient-3');
      if (a && !a.unlocked) {
        a.unlocked = true;
        this.game.pendingAchievements.push(a);
      }
    }

    // Slingshot achievements
    if (probe.orbitCount >= 3) {
      const a = this.game.achievements.find(a => a.id === 'slingshot-3');
      if (a && !a.unlocked) {
        a.unlocked = true;
        this.game.pendingAchievements.push(a);
      }
    }
    if (probe.orbitCount >= 5) {
      const a = this.game.achievements.find(a => a.id === 'slingshot-5');
      if (a && !a.unlocked) {
        a.unlocked = true;
        this.game.pendingAchievements.push(a);
      }
    }

    this.game.checkAchievements();
  }

  private killProbe(probe: Probe) {
    probe.alive = false;
    probe.mesh.visible = false;
    probe.trailLine.visible = false;
  }

  private endLevel() {
    if (this.game.state !== 'playing') return;

    const allCollected = this.targets.every(t => t.collected);
    if (allCollected && this.game.targetsTotal > 0) {
      this.game.levelsCompleted++;
      const stars = this.game.getStars();
      if (stars === 3) this.game.tripleStarCount++;
      if (this.game.probesUsed > 0 && this.game.targetsCollected === this.game.probesUsed) {
        this.game.perfectLevels++;
      }
      this.game.addXP(50 + stars * 25 + this.game.score / 10);
      this.audio.playSuccess();
      this.game.state = 'level-complete';
    } else {
      this.audio.playFail();
      this.game.state = 'game-over';
    }

    this.game.gamesPlayed++;
    this.game.modesPlayed.add(this.game.mode);
    this.game.checkAchievements();
  }
}

