// Input System - handles controller/keyboard input for aiming and launching
class InputControlSystem extends createSystem({}) {
  private game!: GameManager;
  private audio!: AudioManager;
  private probes: Probe[] = [];
  private wells: GravityWell[] = [];
  private predictionLine!: Line;
  private launchIndicator!: Group;
  private launchDir = new Vector3(0, 0, -1);
  private aimOrigin = new Vector3(0, 1.5, 0);
  private chargeTickTimer = 0;

  setRefs(refs: {
    game: GameManager; audio: AudioManager; probes: Probe[];
    wells: GravityWell[]; predictionLine: Line; launchIndicator: Group;
  }) {
    this.game = refs.game;
    this.audio = refs.audio;
    this.probes = refs.probes;
    this.wells = refs.wells;
    this.predictionLine = refs.predictionLine;
    this.launchIndicator = refs.launchIndicator;
  }

  update(delta: number, _time: number) {
    if (this.game.state !== 'playing') {
      this.predictionLine.visible = false;
      this.launchIndicator.visible = false;
      return;
    }

    // XR Controller input
    const right = this.input.xr.gamepads.right;
    const left = this.input.xr.gamepads.left;
    let triggerDown = false;
    let triggerUp = false;
    let triggerHeld = false;
    let slowMoToggle = false;
    let pausePress = false;

    if (right) {
      // Get controller direction
      const grip = this.world.playerSpaceEntities.raySpaces.right.object3D;
      if (grip) {
        const fwd = new Vector3(0, 0, -1);
        fwd.applyQuaternion(grip.quaternion);
        grip.getWorldPosition(this.aimOrigin);
        this.launchDir.copy(fwd).normalize();
      }
      triggerDown = !!right.getButtonDown(InputComponent.Trigger);
      triggerUp = !!right.getButtonUp(InputComponent.Trigger);
      triggerHeld = !!right.getButtonPressed(InputComponent.Trigger);
      slowMoToggle = !!right.getButtonDown(InputComponent.Squeeze);
      pausePress = !!right.getButtonDown(InputComponent.B_Button);
    }
    if (left) {
      if (left.getButtonDown(InputComponent.Squeeze)) slowMoToggle = true;
      if (left.getButtonDown(InputComponent.Y_Button)) pausePress = true;
    }

    // Keyboard input
    if (!right) {
      // Default aim: forward from camera
      const camFwd = new Vector3(0, 0, -1);
      camFwd.applyQuaternion(this.camera.quaternion);
      this.launchDir.copy(camFwd).normalize();
      this.camera.getWorldPosition(this.aimOrigin);

      // Adjust aim with arrow keys / WASD
      if (this.input.keyboard.getKeyPressed('ArrowLeft') || this.input.keyboard.getKeyPressed('KeyA')) {
        this.launchDir.x -= delta * 0.5;
        this.launchDir.normalize();
      }
      if (this.input.keyboard.getKeyPressed('ArrowRight') || this.input.keyboard.getKeyPressed('KeyD')) {
        this.launchDir.x += delta * 0.5;
        this.launchDir.normalize();
      }
      if (this.input.keyboard.getKeyPressed('ArrowUp') || this.input.keyboard.getKeyPressed('KeyW')) {
        this.launchDir.y += delta * 0.3;
        this.launchDir.normalize();
      }
      if (this.input.keyboard.getKeyPressed('ArrowDown') || this.input.keyboard.getKeyPressed('KeyS')) {
        this.launchDir.y -= delta * 0.3;
        this.launchDir.normalize();
      }
    }

    // Keyboard equivalents
    if (this.input.keyboard.getKeyDown('Space')) triggerDown = true;
    if (this.input.keyboard.getKeyUp('Space')) triggerUp = true;
    if (this.input.keyboard.getKeyPressed('Space')) triggerHeld = true;
    if (this.input.keyboard.getKeyDown('ShiftLeft') || this.input.keyboard.getKeyDown('ShiftRight')) slowMoToggle = true;
    if (this.input.keyboard.getKeyDown('Escape') || this.input.keyboard.getKeyDown('KeyP')) pausePress = true;

    // Pause
    if (pausePress) {
      this.game.state = 'paused';
      return;
    }

    // Slow-mo toggle
    if (slowMoToggle) {
      this.game.slowMo = !this.game.slowMo;
      this.game.timeScale = this.game.slowMo ? SLOW_MO_FACTOR : 1;
      if (this.game.slowMo) this.game.slowMoCount++;
    }

    // Charging
    if (triggerDown && !this.game.charging && this.game.probesRemaining > 0) {
      this.game.charging = true;
      this.game.chargeAmount = 0;
    }

    if (this.game.charging && triggerHeld) {
      this.game.chargeAmount = Math.min(this.game.chargeAmount + delta * CHARGE_RATE, 1);

      // Charge sound tick
      this.chargeTickTimer += delta;
      if (this.chargeTickTimer > 0.12) {
        this.chargeTickTimer = 0;
        this.audio.playCharge(this.game.chargeAmount);
      }
    }

    if (this.game.charging && triggerUp) {
      this.game.charging = false;
      this.launchProbe();
    }

    // Update prediction line
    if (this.game.charging && this.game.showTrajectory) {
      const speed = LAUNCH_MIN_SPEED + this.game.chargeAmount * (LAUNCH_MAX_SPEED - LAUNCH_MIN_SPEED);
      const vel = this.launchDir.clone().multiplyScalar(speed);
      const posArr = this.predictionLine.geometry.attributes.position.array as Float32Array;
      const steps = simulateTrajectory(this.aimOrigin, vel, this.wells, PREDICTION_STEPS, PREDICTION_DT, posArr);
      this.predictionLine.geometry.setDrawRange(0, steps);
      this.predictionLine.geometry.attributes.position.needsUpdate = true;
      this.predictionLine.visible = true;
    } else {
      this.predictionLine.visible = false;
    }

    // Update launch indicator
    if (this.game.charging || this.game.probesRemaining > 0) {
      this.launchIndicator.position.copy(this.aimOrigin);
      this.launchIndicator.lookAt(
        this.aimOrigin.x + this.launchDir.x,
        this.aimOrigin.y + this.launchDir.y,
        this.aimOrigin.z + this.launchDir.z,
      );
      this.launchIndicator.visible = true;
    } else {
      this.launchIndicator.visible = false;
    }

    // Haptics during charge
    if (this.game.charging && right) {
      const gp = right.gamepad;
      const actuator = gp?.hapticActuators?.[0] as { pulse?: (i: number, ms: number) => void } | undefined;
      actuator?.pulse?.(this.game.chargeAmount * 0.3, 16);
    }
  }

  private launchProbe() {
    const speed = LAUNCH_MIN_SPEED + this.game.chargeAmount * (LAUNCH_MAX_SPEED - LAUNCH_MIN_SPEED);
    const vel = this.launchDir.clone().multiplyScalar(speed);

    // Find an inactive probe or reuse oldest
    let probe = this.probes.find(p => !p.alive);
    if (!probe) {
      // Reuse oldest
      let oldest = this.probes[0];
      for (const p of this.probes) {
        if (p.age > oldest.age) oldest = p;
      }
      probe = oldest;
    }

    probe.position.copy(this.aimOrigin);
    probe.velocity.copy(vel);
    probe.alive = true;
    probe.age = 0;
    probe.mesh.visible = true;
    probe.trailLine.visible = true;
    probe.mesh.position.copy(this.aimOrigin);
    probe.orbitCount = 0;
    probe.lastWellIdx = -1;
    probe.closestApproach = Infinity;

    // Reset trail
    for (const tp of probe.trailPositions) tp.copy(this.aimOrigin);

    this.game.probesUsed++;
    this.game.probesRemaining--;
    this.game.totalProbesLaunched++;
    this.game.chargeAmount = 0;

    this.audio.playLaunch(speed / LAUNCH_MAX_SPEED);

    // Haptic feedback on launch
    const right = this.input.xr.gamepads.right;
    if (right) {
      const gp = right.gamepad;
      const actuator = gp?.hapticActuators?.[0] as { pulse?: (i: number, ms: number) => void } | undefined;
      actuator?.pulse?.(0.8, 80);
    }
  }
}

