// ============================================================
// MAIN ENTRY
// ============================================================

async function main() {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' },
    render: {
      near: 0.01,
      far: 200,
      defaultLighting: false,
      camera: { position: [0, 1.6, 0], lookAt: [0, 1.5, -3] },
    },
    input: { canvasPointerEvents: true },
    features: {
      grabbing: false,
      locomotion: { browserControls: true },
      physics: false,
    },
  });

  // ---- Scene setup ----
  const game = new GameManager();
  const audio = new AudioManager();

  // Lighting
  const ambientLight = new AmbientLight(0x111133, 0.3);
  world.scene.add(ambientLight);
  const dirLight = new DirectionalLight(0x4444ff, 0.2);
  dirLight.position.set(5, 10, 5);
  world.scene.add(dirLight);

  // Stars and grid
  const stars = createStarField(world.scene);
  let gridGroup = createGridFloor(world.scene, THEMES[game.theme].grid);

  // Fog
  world.scene.fog = new Fog(THEMES[game.theme].fog, 15, 60);
  world.scene.background = new Color(THEMES[game.theme].bg);

  // Particles
  const particles = new ParticlePool(world.scene, 200);

  // Prediction line
  const predictionLine = createPredictionLine(world.scene);

  // Launch indicator
  const launchIndicator = createLaunchIndicator(world.scene);

  // Probe pool
  const probes: Probe[] = [];
  for (let i = 0; i < MAX_PROBES; i++) probes.push(createProbe(world.scene));

  // Gravity wells and targets (managed per level)
  let wells: GravityWell[] = [];
  let targets: Target[] = [];

  // ---- PanelUI entities ----
  // Main menu panel (world-space, in front of player)
  const mainMenuEntity = world.createTransformEntity(undefined, { persistent: true });
  mainMenuEntity.object3D!.position.set(0, 1.8, -2.5);
  mainMenuEntity.addComponent(PanelUI, { config: './ui/main-menu.json', width: 500, height: 600 });

  // HUD panel (head-locked)
  const hudEntity = world.createTransformEntity(undefined, { parent: world.playerHeadEntity, persistent: true });
  hudEntity.object3D!.position.set(0, 0.35, -1.5);
  hudEntity.object3D!.scale.setScalar(0.5);
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json', width: 400, height: 120 });
  hudEntity.addComponent(Follower, { offsetPosition: [0, 0.35, -1.5] });

  // Game over panel
  const gameOverEntity = world.createTransformEntity(undefined, { persistent: true });
  gameOverEntity.object3D!.position.set(0, 1.8, -2.5);
  gameOverEntity.object3D!.visible = false;
  gameOverEntity.addComponent(PanelUI, { config: './ui/game-over.json', width: 450, height: 500 });

  // Mode select panel
  const modeSelectEntity = world.createTransformEntity(undefined, { persistent: true });
  modeSelectEntity.object3D!.position.set(0, 1.8, -2.5);
  modeSelectEntity.object3D!.visible = false;
  modeSelectEntity.addComponent(PanelUI, { config: './ui/mode-select.json', width: 500, height: 550 });

  // How to play panel
  const howToPlayEntity = world.createTransformEntity(undefined, { persistent: true });
  howToPlayEntity.object3D!.position.set(0, 1.8, -2.5);
  howToPlayEntity.object3D!.visible = false;
  howToPlayEntity.addComponent(PanelUI, { config: './ui/how-to-play.json', width: 450, height: 400 });

  // Settings panel
  const settingsEntity = world.createTransformEntity(undefined, { persistent: true });
  settingsEntity.object3D!.position.set(0, 1.8, -2.5);
  settingsEntity.object3D!.visible = false;
  settingsEntity.addComponent(PanelUI, { config: './ui/settings.json', width: 450, height: 400 });

  // Stats panel
  const statsEntity = world.createTransformEntity(undefined, { persistent: true });
  statsEntity.object3D!.position.set(0, 1.8, -2.5);
  statsEntity.object3D!.visible = false;
  statsEntity.addComponent(PanelUI, { config: './ui/stats.json', width: 500, height: 550 });

  // Achievements panel
  const achEntity = world.createTransformEntity(undefined, { persistent: true });
  achEntity.object3D!.position.set(0, 1.8, -2.5);
  achEntity.object3D!.visible = false;
  achEntity.addComponent(PanelUI, { config: './ui/achievements.json', width: 500, height: 550 });

  // Pause panel
  const pauseEntity = world.createTransformEntity(undefined, { persistent: true });
  pauseEntity.object3D!.position.set(0, 1.8, -2.5);
  pauseEntity.object3D!.visible = false;
  pauseEntity.addComponent(PanelUI, { config: './ui/pause.json', width: 400, height: 300 });

  // Theme select panel
  const themeEntity = world.createTransformEntity(undefined, { persistent: true });
  themeEntity.object3D!.position.set(0, 1.8, -2.5);
  themeEntity.object3D!.visible = false;
  themeEntity.addComponent(PanelUI, { config: './ui/theme-select.json', width: 450, height: 450 });

  // Notification panel (top, head-locked)
  const notifEntity = world.createTransformEntity(undefined, { parent: world.playerHeadEntity, persistent: true });
  notifEntity.object3D!.position.set(0, 0.55, -1.5);
  notifEntity.object3D!.scale.setScalar(0.5);
  notifEntity.object3D!.visible = false;
  notifEntity.addComponent(PanelUI, { config: './ui/notification.json', width: 300, height: 80 });
  notifEntity.addComponent(Follower, { offsetPosition: [0, 0.55, -1.5] });

  // Power gauge (below HUD, head-locked)
  const powerEntity = world.createTransformEntity(undefined, { parent: world.playerHeadEntity, persistent: true });
  powerEntity.object3D!.position.set(0, 0.15, -1.5);
  powerEntity.object3D!.scale.setScalar(0.5);
  powerEntity.object3D!.visible = false;
  powerEntity.addComponent(PanelUI, { config: './ui/power-gauge.json', width: 250, height: 60 });
  powerEntity.addComponent(Follower, { offsetPosition: [0, 0.15, -1.5] });

  // Level complete panel
  const lvlCompleteEntity = world.createTransformEntity(undefined, { persistent: true });
  lvlCompleteEntity.object3D!.position.set(0, 1.8, -2.5);
  lvlCompleteEntity.object3D!.visible = false;
  lvlCompleteEntity.addComponent(PanelUI, { config: './ui/level-complete.json', width: 350, height: 200 });

  // Daily challenge panel
  const dailyEntity = world.createTransformEntity(undefined, { persistent: true });
  dailyEntity.object3D!.position.set(0, 1.8, -2.5);
  dailyEntity.object3D!.visible = false;
  dailyEntity.addComponent(PanelUI, { config: './ui/daily-challenge.json', width: 500, height: 500 });

  // ---- Game flow functions ----
  function clearLevel() {
    for (const well of wells) world.scene.remove(well.group);
    for (const target of targets) world.scene.remove(target.group);
    for (const probe of probes) {
      probe.alive = false;
      probe.mesh.visible = false;
      probe.trailLine.visible = false;
    }
    wells = [];
    targets = [];
  }

  function startGame(mode: GameMode, level: number) {
    clearLevel();
    game.state = 'playing';
    game.mode = mode;
    game.level = level;
    game.score = 0;
    game.probesUsed = 0;
    game.targetsCollected = 0;
    game.elapsedTime = 0;
    game.combo = 0;
    game.bestCombo = 0;
    game.lastCollectTime = 0;
    game.charging = false;
    game.chargeAmount = 0;
    game.slowMo = false;
    game.timeScale = 1;

    // Generate level
    const levelConfig = generateLevel(level, mode);
    game.currentLevel = levelConfig;
    game.probesRemaining = levelConfig.probeLimit;
    game.targetsTotal = levelConfig.targets.length;

    // Create wells
    for (const wc of levelConfig.wells) {
      wells.push(createGravityWell(world.scene, wc));
    }

    // Create targets
    for (const tc of levelConfig.targets) {
      targets.push(createTarget(world.scene, tc));
    }

    // Update system refs
    game.wells = wells;
    game.probes = probes;
    game.targets = targets;
    orbitSys.setRefs({ game, audio, particles, probes, wells, targets });
    inputSys.setRefs({ game, audio, probes, wells, predictionLine, launchIndicator });

    // Start background audio
    audio.startDrone();
  }

  function applyTheme(theme: ThemeName) {
    const colors = THEMES[theme];
    world.scene.background = new Color(colors.bg);
    if (world.scene.fog) (world.scene.fog as Fog).color.setHex(colors.fog);
    ambientLight.color.setHex(colors.ambient);

    // Recreate grid
    world.scene.remove(gridGroup);
    gridGroup = createGridFloor(world.scene, colors.grid);
  }

  // ---- Register systems ----
  world.registerSystem(OrbitPhysicsSystem);
  world.registerSystem(InputControlSystem);
  world.registerSystem(GameUISystem);

  const orbitSys = world.getSystem(OrbitPhysicsSystem)!;
  const inputSys = world.getSystem(InputControlSystem)!;
  const uiSys = world.getSystem(GameUISystem)!;

  orbitSys.setRefs({ game, audio, particles, probes, wells, targets });
  inputSys.setRefs({ game, audio, probes, wells, predictionLine, launchIndicator });
  uiSys.setRefs({
    game,
    audio,
    onStartGame: startGame,
    onApplyTheme: applyTheme,
  });

  // Add ambient orbiting decoration planets far away
  for (let i = 0; i < 5; i++) {
    const r = 0.5 + Math.random() * 1.5;
    const geo = new SphereGeometry(r, 16, 16);
    const mat = new MeshStandardMaterial({
      color: PLANET_COLORS[i],
      emissive: PLANET_COLORS[i],
      emissiveIntensity: 0.2,
      roughness: 0.6,
    });
    const mesh = new Mesh(geo, mat);
    const dist = 30 + Math.random() * 40;
    const angle = (i / 5) * Math.PI * 2;
    mesh.position.set(Math.cos(angle) * dist, (Math.random() - 0.5) * 20, Math.sin(angle) * dist);
    world.scene.add(mesh);
  }
}

main().catch(console.error);
