{"content":"import {
  World,
  createSystem,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  UIKit,
  eq,
  Follower,
  InputComponent,
  Mesh,
  Group,
  SphereGeometry,
  CylinderGeometry,
  TorusGeometry,
  OctahedronGeometry,
  BufferGeometry,
  Float32BufferAttribute,
  MeshStandardMaterial,
  MeshBasicMaterial,
  LineBasicMaterial,
  PointsMaterial,
  Points,
  LineSegments,
  Line,
  Color,
  Vector3,
  AmbientLight,
  PointLight,
  DirectionalLight,
  Fog,
  AdditiveBlending,
  Object3D,
  type Entity,
} from '@iwsdk/core';

// ============================================================
// CONSTANTS
// ============================================================

const G_CONSTANT = 6.0;
const MAX_PROBES = 20;
const PROBE_RADIUS = 0.08;
const TARGET_RADIUS = 0.15;
const TRAIL_LENGTH = 120;
const MAX_DISTANCE = 30;
const LAUNCH_MIN_SPEED = 2;
const LAUNCH_MAX_SPEED = 12;
const CHARGE_RATE = 1.5;
const PREDICTION_STEPS = 200;
const PREDICTION_DT = 0.03;
const SLOW_MO_FACTOR = 0.25;
const COMBO_WINDOW = 3.0;

// ============================================================
// TYPES
// ============================================================

type GameMode = 'classic' | 'slingshot' | 'time-trial' | 'precision' | 'chaos' | 'zen' | 'survival' | 'daily';
type GameState = 'menu' | 'playing' | 'paused' | 'level-complete' | 'game-over';
type ThemeName = 'deep-space' | 'nebula' | 'solar' | 'ice' | 'void';

interface ThemeColors { bg: number; fog: number; ambient: number; grid: number; accent: number; }

const THEMES: Record<ThemeName, ThemeColors> = {
  'deep-space': { bg: 0x020210, fog: 0x020210, ambient: 0x111133, grid: 0x1a1a4a, accent: 0x00ffff },
  'nebula': { bg: 0x0d0020, fog: 0x0d0020, ambient: 0x221133, grid: 0x331155, accent: 0xff44ff },
  'solar': { bg: 0x100800, fog: 0x100800, ambient: 0x332200, grid: 0x443311, accent: 0xffaa00 },
  'ice': { bg: 0x001020, fog: 0x001020, ambient: 0x112233, grid: 0x224466, accent: 0x88ddff },
  'void': { bg: 0x000800, fog: 0x000800, ambient: 0x002200, grid: 0x003300, accent: 0x00ff88 },
};

interface GravityWell {
  group: Group; position: Vector3; mass: number; radius: number;
  color: number; glowMesh: Mesh; ringMesh: Mesh; fieldLines: Line[]; pulsePhase: number;
}

interface Probe {
  mesh: Mesh; trailLine: Line; trailPositions: Vector3[];
  position: Vector3; velocity: Vector3; alive: boolean; age: number;
  orbitCount: number; lastWellIdx: number; closestApproach: number;
}

interface Target {
  group: Group; position: Vector3; collected: boolean;
  pulsePhase: number; points: number;
}

interface LevelConfig {
  wells: { x: number; y: number; z: number; mass: number; radius: number; color: number }[];
  targets: { x: number; y: number; z: number; points: number }[];
  probeLimit: number; timeLimit: number; name: string;
}

interface Achievement { id: string; name: string; desc: string; unlocked: boolean; }

// ============================================================
// KEYBOARD STATE (browser fallback since XRInputManager has no keyboard)
// ============================================================

class KeyState {
  private pressed = new Set<string>();
  private justDown = new Set<string>();
  private justUp = new Set<string>();

  constructor() {
    document.addEventListener('keydown', (e) => {
      if (!this.pressed.has(e.code)) this.justDown.add(e.code);
      this.pressed.add(e.code);
    });
    document.addEventListener('keyup', (e) => {
      this.pressed.delete(e.code);
      this.justUp.add(e.code);
    });
  }

  getKeyPressed(code: string): boolean { return this.pressed.has(code); }
  getKeyDown(code: string): boolean { return this.justDown.has(code); }
  getKeyUp(code: string): boolean { return this.justUp.has(code); }

  endFrame() {
    this.justDown.clear();
    this.justUp.clear();
  }
}

// ============================================================
// AUDIO MANAGER
// ============================================================

class AudioManager {
  private ctx: AudioContext | null = null;
  private masterGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private droneOsc: OscillatorNode | null = null;
  musicVolume = 0.8;
  sfxVolume = 1.0;

  private ensureCtx() {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.masterGain = this.ctx.createGain();
      this.masterGain.connect(this.ctx.destination);
      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVolume * 0.3;
      this.musicGain.connect(this.masterGain);
      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.masterGain);
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  startDrone() {
    const ctx = this.ensureCtx();
    if (this.droneOsc) return;
    this.droneOsc = ctx.createOscillator();
    this.droneOsc.type = 'sine';
    this.droneOsc.frequency.value = 55;
    const g = ctx.createGain();
    g.gain.value = 0.08;
    this.droneOsc.connect(g);
    g.connect(this.musicGain!);
    this.droneOsc.start();
    const h = ctx.createOscillator();
    h.type = 'sine';
    h.frequency.value = 82.5;
    const hg = ctx.createGain();
    hg.gain.value = 0.04;
    h.connect(hg);
    hg.connect(this.musicGain!);
    h.start();
  }

  playLaunch(power: number) {
    const ctx = this.ensureCtx();
    const o = ctx.createOscillator();
    o.type = 'sawtooth';
    o.frequency.value = 200 + power * 400;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.15, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.3);
    o.connect(g); g.connect(this.sfxGain!);
    o.start(); o.stop(ctx.currentTime + 0.3);
  }

  playCollect(combo: number) {
    const ctx = this.ensureCtx();
    const baseFreq = 440 * Math.pow(2, combo / 12);
    for (let i = 0; i < 3; i++) {
      const o = ctx.createOscillator();
      o.type = 'sine';
      o.frequency.value = baseFreq * (1 + i * 0.5);
      const g = ctx.createGain();
      g.gain.setValueAtTime(0.12, ctx.currentTime + i * 0.05);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.05 + 0.3);
      o.connect(g); g.connect(this.sfxGain!);
      o.start(ctx.currentTime + i * 0.05); o.stop(ctx.currentTime + i * 0.05 + 0.3);
    }
  }

  playCrash() {
    const ctx = this.ensureCtx();
    const bufSize = ctx.sampleRate * 0.2;
    const buf = ctx.createBuffer(1, bufSize, ctx.sampleRate);
    const data = buf.getChannelData(0);
