  isPressed(code: string) { return this.pressed.has(code); }
  isDown(code: string) { return this.justDown.has(code); }
  isUp(code: string) { return this.justUp.has(code); }
  endFrame() { this.justDown.clear(); this.justUp.clear(); }
}

